/**
 * Analytics models for the dashboard API.
 */

/**
 * Aggregate summary statistics across the system.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics data.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregates data for the analytics dashboard.
 *
 * Depends on:
 * - UserRepository (data layer) for user statistics
 * - OrderRepository (data layer) for order and revenue statistics
 *
 * This is a read-only service that computes aggregate views
 * over existing user and order data.
 */

import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get aggregate summary statistics.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    const userIdsWithOrders = new Set(orders.map((order) => order.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    const lastActive = orders.length > 0
      ? orders.reduce((latest, order) =>
          order.createdAt > latest ? order.createdAt : latest,
        orders[0].createdAt)
      : user.createdAt;

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get time-series trend data for a metric within a date range.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric} from ${startDate.toISOString()} to ${endDate.toISOString()}`);

    if (metric === 'orders') {
      return this.getOrderTrends(startDate, endDate);
    }

    if (metric === 'revenue') {
      return this.getRevenueTrends(startDate, endDate);
    }

    if (metric === 'users') {
      return this.getUserTrends(startDate, endDate);
    }

    throw new Error(`Unknown metric: ${metric}`);
  }

  private getOrderTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    return this.aggregateByDay(orders, 'orders', (items) => items.length);
  }

  private getRevenueTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    return this.aggregateByDay(orders, 'revenue', (items) =>
      items.reduce((sum, order) => sum + order.total, 0),
    );
  }

  private getUserTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const users = this.userRepository.findAll(
      (user) => user.createdAt >= startDate && user.createdAt <= endDate,
    );

    return this.aggregateByDay(users, 'users', (items) => items.length);
  }

  private aggregateByDay<T extends { createdAt: Date }>(
    items: T[],
    metric: string,
    aggregate: (items: T[]) => number,
  ): TrendPoint[] {
    const byDay = new Map<string, T[]>();

    for (const item of items) {
      const dayKey = item.createdAt.toISOString().split('T')[0];
      const existing = byDay.get(dayKey) ?? [];
      existing.push(item);
      byDay.set(dayKey, existing);
    }

    const points: TrendPoint[] = [];
    for (const [dayKey, dayItems] of byDay) {
      points.push({
        timestamp: new Date(dayKey + 'T00:00:00.000Z'),
        metric,
        value: aggregate(dayItems),
      });
    }

    points.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
    return points;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const makeUser = (overrides?: Partial<User>): User => ({
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2024-01-15'),
    updatedAt: new Date('2024-01-15'),
    ...overrides,
  });

  const makeOrder = (overrides?: Partial<Order>): Order => ({
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date('2024-02-01'),
    updatedAt: new Date('2024-02-01'),
    ...overrides,
  });

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats from users and orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      userRepo.save(makeUser({ id: 'user-3', email: 'carol@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 30 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 20 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(100);
      expect(summary.activeUsers).toBe(2);
    });

    it('should count active users as those with orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 10 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(2);
      expect(summary.activeUsers).toBe(1);
    });
  });

  describe('getUserAnalytics', () => {
    it('should return analytics for a user with orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 50, createdAt: new Date('2024-02-01') }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 30, createdAt: new Date('2024-03-15') }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(80);
      expect(analytics.lastActive).toEqual(new Date('2024-03-15'));
    });

    it('should return zero stats for a user with no orders', () => {
      userRepo.save(makeUser({ id: 'user-1', createdAt: new Date('2024-01-15') }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toEqual(new Date('2024-01-15'));
    });

    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });
  });

  describe('getTrends', () => {
    it('should return order count trends by day', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({ id: 'order-1', createdAt: new Date('2024-02-01T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'order-2', createdAt: new Date('2024-02-01T14:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'order-3', createdAt: new Date('2024-02-02T09:00:00Z') }));

      const trends = service.getTrends('orders', new Date('2024-02-01'), new Date('2024-02-03'));

      expect(trends).toHaveLength(2);
      expect(trends[0].timestamp).toEqual(new Date('2024-02-01T00:00:00.000Z'));
      expect(trends[0].metric).toBe('orders');
      expect(trends[0].value).toBe(2);
      expect(trends[1].value).toBe(1);
    });

    it('should return revenue trends by day', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({ id: 'order-1', total: 50, createdAt: new Date('2024-02-01T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'order-2', total: 30, createdAt: new Date('2024-02-01T14:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'order-3', total: 20, createdAt: new Date('2024-02-02T09:00:00Z') }));

      const trends = service.getTrends('revenue', new Date('2024-02-01'), new Date('2024-02-03'));

      expect(trends).toHaveLength(2);
      expect(trends[0].metric).toBe('revenue');
      expect(trends[0].value).toBe(80);
      expect(trends[1].value).toBe(20);
    });

    it('should return user registration trends by day', () => {
      userRepo.save(makeUser({ id: 'user-1', createdAt: new Date('2024-02-01T10:00:00Z') }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com', createdAt: new Date('2024-02-01T14:00:00Z') }));
      userRepo.save(makeUser({ id: 'user-3', email: 'carol@example.com', createdAt: new Date('2024-02-02T09:00:00Z') }));

      const trends = service.getTrends('users', new Date('2024-02-01'), new Date('2024-02-03'));

      expect(trends).toHaveLength(2);
      expect(trends[0].metric).toBe('users');
      expect(trends[0].value).toBe(2);
      expect(trends[1].value).toBe(1);
    });

    it('should return empty array when no data in range', () => {
      const trends = service.getTrends('orders', new Date('2024-06-01'), new Date('2024-06-30'));

      expect(trends).toHaveLength(0);
    });

    it('should throw for unknown metric', () => {
      expect(() =>
        service.getTrends('unknown', new Date('2024-01-01'), new Date('2024-12-31')),
      ).toThrow('Unknown metric: unknown');
    });

    it('should sort trend points chronologically', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      orderRepo.save(makeOrder({ id: 'order-1', createdAt: new Date('2024-02-03T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'order-2', createdAt: new Date('2024-02-01T10:00:00Z') }));

      const trends = service.getTrends('orders', new Date('2024-02-01'), new Date('2024-02-04'));

      expect(trends[0].timestamp.getTime()).toBeLessThan(trends[1].timestamp.getTime());
    });
  });
});

